+// CORSOptions specifies the configuration used by CORS() middleware and by
+// the Mux's EnableCORS/EnableCORSWithOptions methods to control
+// Cross-Origin Resource Sharing behavior.
+type CORSOptions struct {
+	// AllowOrigin is the value written to the Access-Control-Allow-Origin
+	// response header.
+	AllowOrigin string
+
+	// AllowMethods is a static list of methods to advertise in the
+	// Access-Control-Allow-Methods header during preflight requests. When
+	// left empty, the methods actually registered for the requested
+	// resource are detected automatically.
+	AllowMethods []string
+
+	// AllowHeaders is the list of headers a client is allowed to send,
+	// written to the Access-Control-Allow-Headers response header.
+	AllowHeaders []string
+
+	// ExposeHeaders is the list of headers exposed to the browser via the
+	// Access-Control-Expose-Headers response header.
+	ExposeHeaders []string
+
+	// MaxAge is the number of seconds a preflight response may be cached,
+	// written to the Access-Control-Max-Age header.
+	MaxAge int
+
+	// AllowCredentials sets the Access-Control-Allow-Credentials header.
+	AllowCredentials bool
+}
+
+// DefaultCORSOptions returns a CORSOptions with permissive, sensible
+// defaults: any origin, a common set of request headers, and an hour of
+// preflight caching.
+func DefaultCORSOptions() CORSOptions {
+	return CORSOptions{
+		AllowOrigin:   "*",
+		AllowHeaders:  []string{"Accept", "Authorization", "Content-Type", "X-CSRF-Token"},
+		ExposeHeaders: []string{},
+		MaxAge:        3600,
+	}
+}
+
+// CORS returns a middleware that applies the given CORSOptions to every
+// response, and automatically resolves preflight OPTIONS requests with a
+// 204, detecting the methods available for the requested resource when
+// options.AllowMethods isn't set explicitly.
+func CORS(options CORSOptions) func(http.Handler) http.Handler {
+	return func(next http.Handler) http.Handler {
+		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
+			setCORSHeaders(w, options)
+
+			if r.Method == http.MethodOptions {
+				methods := options.AllowMethods
+				if len(methods) == 0 {
+					methods = resourceMethodsForRequest(r)
+				}
+				if len(methods) > 0 {
+					w.Header().Set("Access-Control-Allow-Methods", strings.Join(methods, ", "))
+				}
+				w.WriteHeader(http.StatusNoContent)
+				return
+			}
+
+			next.ServeHTTP(w, r)
+		})
+	}
+}
+
+// setCORSHeaders writes the static, non-preflight-specific CORS response
+// headers derived from options.
+func setCORSHeaders(w http.ResponseWriter, options CORSOptions) {
+	header := w.Header()
+	if options.AllowOrigin != "" {
+		header.Set("Access-Control-Allow-Origin", options.AllowOrigin)
+	}
+	if len(options.AllowHeaders) > 0 {
+		header.Set("Access-Control-Allow-Headers", strings.Join(options.AllowHeaders, ", "))
+	}
+	if len(options.ExposeHeaders) > 0 {
+		header.Set("Access-Control-Expose-Headers", strings.Join(options.ExposeHeaders, ", "))
+	}
+	if options.MaxAge > 0 {
+		header.Set("Access-Control-Max-Age", strconv.Itoa(options.MaxAge))
+	}
+	if options.AllowCredentials {
+		header.Set("Access-Control-Allow-Credentials", "true")
+	}
+}
